--
-- Name: grant_pg_cron_access(); Type: FUNCTION; Schema: extensions; Owner: supabase_admin
--

CREATE FUNCTION extensions.grant_pg_cron_access() RETURNS event_trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF EXISTS (
    SELECT
    FROM pg_event_trigger_ddl_commands() AS ev
    JOIN pg_extension AS ext
    ON ev.objid = ext.oid
    WHERE ext.extname = 'pg_cron'
  )
  THEN
    grant usage on schema cron to postgres with grant option;

    alter default privileges in schema cron grant all on tables to postgres with grant option;
    alter default privileges in schema cron grant all on functions to postgres with grant option;
    alter default privileges in schema cron grant all on sequences to postgres with grant option;

    alter default privileges for user supabase_admin in schema cron grant all
        on sequences to postgres with grant option;
    alter default privileges for user supabase_admin in schema cron grant all
        on tables to postgres with grant option;
    alter default privileges for user supabase_admin in schema cron grant all
        on functions to postgres with grant option;

    grant all privileges on all tables in schema cron to postgres with grant option;
    revoke all on table cron.job from postgres;
    grant select on table cron.job to postgres with grant option;
  END IF;
END;
$$;


ALTER FUNCTION extensions.grant_pg_cron_access() OWNER TO supabase_admin;

--
-- Name: FUNCTION grant_pg_cron_access(); Type: COMMENT; Schema: extensions; Owner: supabase_admin
--

COMMENT ON FUNCTION extensions.grant_pg_cron_access() IS 'Grants access to pg_cron';


--
-- Name: grant_pg_graphql_access(); Type: FUNCTION; Schema: extensions; Owner: supabase_admin
--

CREATE FUNCTION extensions.grant_pg_graphql_access() RETURNS event_trigger
    LANGUAGE plpgsql
    AS $_$
DECLARE
    func_is_graphql_resolve bool;
BEGIN
    func_is_graphql_resolve = (
        SELECT n.proname = 'resolve'
        FROM pg_event_trigger_ddl_commands() AS ev
        LEFT JOIN pg_catalog.pg_proc AS n
        ON ev.objid = n.oid
    );

    IF func_is_graphql_resolve
    THEN
        -- Update public wrapper to pass all arguments through to the pg_graphql resolve func
        DROP FUNCTION IF EXISTS graphql_public.graphql;
        create or replace function graphql_public.graphql(
            "operationName" text default null,
            query text default null,
            variables jsonb default null,
            extensions jsonb default null
        )
            returns jsonb
            language sql
        as $$
            select graphql.resolve(
                query := query,
                variables := coalesce(variables, '{}'),
                "operationName" := "operationName",
                extensions := extensions
            );
        $$;

        -- This hook executes when `graphql.resolve` is created. That is not necessarily the last
        -- function in the extension so we need to grant permissions on existing entities AND
        -- update default permissions to any others that are created after `graphql.resolve`
        grant usage on schema graphql to postgres, anon, authenticated, service_role;
        grant select on all tables in schema graphql to postgres, anon, authenticated, service_role;
        grant execute on all functions in schema graphql to postgres, anon, authenticated, service_role;
        grant all on all sequences in schema graphql to postgres, anon, authenticated, service_role;
        alter default privileges in schema graphql grant all on tables to postgres, anon, authenticated, service_role;
        alter default privileges in schema graphql grant all on functions to postgres, anon, authenticated, service_role;
        alter default privileges in schema graphql grant all on sequences to postgres, anon, authenticated, service_role;

        -- Allow postgres role to allow granting usage on graphql and graphql_public schemas to custom roles
        grant usage on schema graphql_public to postgres with grant option;
        grant usage on schema graphql to postgres with grant option;
    END IF;

END;
$_$;


ALTER FUNCTION extensions.grant_pg_graphql_access() OWNER TO supabase_admin;

--
-- Name: FUNCTION grant_pg_graphql_access(); Type: COMMENT; Schema: extensions; Owner: supabase_admin
--

COMMENT ON FUNCTION extensions.grant_pg_graphql_access() IS 'Grants access to pg_graphql';


--
-- Name: grant_pg_net_access(); Type: FUNCTION; Schema: extensions; Owner: supabase_admin
--

CREATE FUNCTION extensions.grant_pg_net_access() RETURNS event_trigger
    LANGUAGE plpgsql
    AS $$
  BEGIN
    IF EXISTS (
      SELECT 1
      FROM pg_event_trigger_ddl_commands() AS ev
      JOIN pg_extension AS ext
      ON ev.objid = ext.oid
      WHERE ext.extname = 'pg_net'
    )
    THEN
      GRANT USAGE ON SCHEMA net TO supabase_functions_admin, postgres, anon, authenticated, service_role;

      IF EXISTS (
        SELECT FROM pg_extension
        WHERE extname = 'pg_net'
        -- all versions in use on existing projects as of 2025-02-20
        -- version 0.12.0 onwards don't need these applied
        AND extversion IN ('0.2', '0.6', '0.7', '0.7.1', '0.8', '0.10.0', '0.11.0')
      ) THEN
        ALTER function net.http_get(url text, params jsonb, headers jsonb, timeout_milliseconds integer) SECURITY DEFINER;
        ALTER function net.http_post(url text, body jsonb, params jsonb, headers jsonb, timeout_milliseconds integer) SECURITY DEFINER;

        ALTER function net.http_get(url text, params jsonb, headers jsonb, timeout_milliseconds integer) SET search_path = net;
        ALTER function net.http_post(url text, body jsonb, params jsonb, headers jsonb, timeout_milliseconds integer) SET search_path = net;

        REVOKE ALL ON FUNCTION net.http_get(url text, params jsonb, headers jsonb, timeout_milliseconds integer) FROM PUBLIC;
        REVOKE ALL ON FUNCTION net.http_post(url text, body jsonb, params jsonb, headers jsonb, timeout_milliseconds integer) FROM PUBLIC;

        GRANT EXECUTE ON FUNCTION net.http_get(url text, params jsonb, headers jsonb, timeout_milliseconds integer) TO supabase_functions_admin, postgres, anon, authenticated, service_role;
        GRANT EXECUTE ON FUNCTION net.http_post(url text, body jsonb, params jsonb, headers jsonb, timeout_milliseconds integer) TO supabase_functions_admin, postgres, anon, authenticated, service_role;
      END IF;
    END IF;
  END;
  $$;


ALTER FUNCTION extensions.grant_pg_net_access() OWNER TO supabase_admin;

--
-- Name: FUNCTION grant_pg_net_access(); Type: COMMENT; Schema: extensions; Owner: supabase_admin
--

COMMENT ON FUNCTION extensions.grant_pg_net_access() IS 'Grants access to pg_net';


--
-- Name: pgrst_ddl_watch(); Type: FUNCTION; Schema: extensions; Owner: supabase_admin
--

CREATE FUNCTION extensions.pgrst_ddl_watch() RETURNS event_trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN SELECT * FROM pg_event_trigger_ddl_commands()
  LOOP
    IF cmd.command_tag IN (
      'CREATE SCHEMA', 'ALTER SCHEMA'
    , 'CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO', 'ALTER TABLE'
    , 'CREATE FOREIGN TABLE', 'ALTER FOREIGN TABLE'
    , 'CREATE VIEW', 'ALTER VIEW'
    , 'CREATE MATERIALIZED VIEW', 'ALTER MATERIALIZED VIEW'
    , 'CREATE FUNCTION', 'ALTER FUNCTION'
    , 'CREATE TRIGGER'
    , 'CREATE TYPE', 'ALTER TYPE'
    , 'CREATE RULE'
    , 'COMMENT'
    )
    -- don't notify in case of CREATE TEMP table or other objects created on pg_temp
    AND cmd.schema_name is distinct from 'pg_temp'
    THEN
      NOTIFY pgrst, 'reload schema';
    END IF;
  END LOOP;
END; $$;


ALTER FUNCTION extensions.pgrst_ddl_watch() OWNER TO supabase_admin;

--
-- Name: pgrst_drop_watch(); Type: FUNCTION; Schema: extensions; Owner: supabase_admin
--

CREATE FUNCTION extensions.pgrst_drop_watch() RETURNS event_trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  obj record;
BEGIN
  FOR obj IN SELECT * FROM pg_event_trigger_dropped_objects()
  LOOP
    IF obj.object_type IN (
      'schema'
    , 'table'
    , 'foreign table'
    , 'view'
    , 'materialized view'
    , 'function'
    , 'trigger'
    , 'type'
    , 'rule'
    )
    AND obj.is_temporary IS false -- no pg_temp objects
    THEN
      NOTIFY pgrst, 'reload schema';
    END IF;
  END LOOP;
END; $$;


ALTER FUNCTION extensions.pgrst_drop_watch() OWNER TO supabase_admin;

--
-- Name: set_graphql_placeholder(); Type: FUNCTION; Schema: extensions; Owner: supabase_admin
--

CREATE FUNCTION extensions.set_graphql_placeholder() RETURNS event_trigger
    LANGUAGE plpgsql
    AS $_$
    DECLARE
    graphql_is_dropped bool;
    BEGIN
    graphql_is_dropped = (
        SELECT ev.schema_name = 'graphql_public'
        FROM pg_event_trigger_dropped_objects() AS ev
        WHERE ev.schema_name = 'graphql_public'
    );

    IF graphql_is_dropped
    THEN
        create or replace function graphql_public.graphql(
            "operationName" text default null,
            query text default null,
            variables jsonb default null,
            extensions jsonb default null
        )
            returns jsonb
            language plpgsql
        as $$
            DECLARE
                server_version float;
            BEGIN
                server_version = (SELECT (SPLIT_PART((select version()), ' ', 2))::float);

                IF server_version >= 14 THEN
                    RETURN jsonb_build_object(
                        'errors', jsonb_build_array(
                            jsonb_build_object(
                                'message', 'pg_graphql extension is not enabled.'
                            )
                        )
                    );
                ELSE
                    RETURN jsonb_build_object(
                        'errors', jsonb_build_array(
                            jsonb_build_object(
                                'message', 'pg_graphql is only available on projects running Postgres 14 onwards.'
                            )
                        )
                    );
                END IF;
            END;
        $$;
    END IF;

    END;
$_$;


ALTER FUNCTION extensions.set_graphql_placeholder() OWNER TO supabase_admin;

--
-- Name: FUNCTION set_graphql_placeholder(); Type: COMMENT; Schema: extensions; Owner: supabase_admin
--

COMMENT ON FUNCTION extensions.set_graphql_placeholder() IS 'Reintroduces placeholder function for graphql_public.graphql';


--
-- Name: get_auth(text); Type: FUNCTION; Schema: pgbouncer; Owner: supabase_admin
--

CREATE FUNCTION pgbouncer.get_auth(p_usename text) RETURNS TABLE(username text, password text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $_$
  BEGIN
      RAISE DEBUG 'PgBouncer auth request: %', p_usename;

      RETURN QUERY
      SELECT
          rolname::text,
          CASE WHEN rolvaliduntil < now()
              THEN null
              ELSE rolpassword::text
          END
      FROM pg_authid
      WHERE rolname=$1 and rolcanlogin;
  END;
  $_$;


ALTER FUNCTION pgbouncer.get_auth(p_usename text) OWNER TO supabase_admin;

--
-- Name: approve_contribution(bigint, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.approve_contribution(contribution_id bigint, admin_user_id text DEFAULT 'system'::text) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  contribution_record iebc_office_contributions%ROWTYPE;
  new_office_id bigint;
  result jsonb;
BEGIN
  -- Get the contribution data
  SELECT * INTO contribution_record 
  FROM iebc_office_contributions 
  WHERE id = contribution_id;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Contribution not found');
  END IF;
  
  -- Update contribution status
  UPDATE iebc_office_contributions 
  SET 
    status = 'approved',
    reviewer_id = admin_user_id,
    reviewed_at = NOW()
  WHERE id = contribution_id;
  
  -- If original_office_id exists, update that office
  IF contribution_record.original_office_id IS NOT NULL THEN
    UPDATE iebc_offices 
    SET 
      verified_latitude = contribution_record.submitted_latitude,
      verified_longitude = contribution_record.submitted_longitude,
      verified_at = NOW(),
      verifier_id = admin_user_id,
      verification_source = 'crowdsource',
      contributor_image_url = contribution_record.image_public_url,
      geom = ST_SetSRID(ST_MakePoint(contribution_record.submitted_longitude, contribution_record.submitted_latitude), 4326),
      updated_at = NOW()
    WHERE id = contribution_record.original_office_id;
    
    result := jsonb_build_object(
      'action', 'updated',
      'office_id', contribution_record.original_office_id,
      'contribution_id', contribution_id
    );
  ELSE
    -- Insert new office record
    INSERT INTO iebc_offices (
      county,
      constituency_code,
      constituency,
      constituency_name,
      office_location,
      landmark,
      latitude,
      longitude,
      verified_latitude,
      verified_longitude,
      verified_at,
      verifier_id,
      verification_source,
      contributor_image_url,
      geom,
      verified,
      source,
      geocode_method,
      geocode_confidence
    ) VALUES (
      contribution_record.submitted_county,
      contribution_record.submitted_constituency_code,
      contribution_record.submitted_constituency,
      contribution_record.submitted_constituency,
      contribution_record.submitted_office_location,
      contribution_record.submitted_landmark,
      contribution_record.submitted_latitude,
      contribution_record.submitted_longitude,
      contribution_record.submitted_latitude,
      contribution_record.submitted_longitude,
      NOW(),
      admin_user_id,
      'crowdsource',
      contribution_record.image_public_url,
      ST_SetSRID(ST_MakePoint(contribution_record.submitted_longitude, contribution_record.submitted_latitude), 4326),
      true,
      'crowdsource',
      'manual_contribution',
      0.95
    )
    RETURNING id INTO new_office_id;
    
    result := jsonb_build_object(
      'action', 'created',
      'office_id', new_office_id,
      'contribution_id', contribution_id
    );
  END IF;
  
  RETURN result;
END;
$$;


ALTER FUNCTION public.approve_contribution(contribution_id bigint, admin_user_id text) OWNER TO postgres;

--
-- Name: archive_contribution(integer, text, text, text, text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.archive_contribution(p_contribution_id integer, p_action_type text, p_actor text, p_review_notes text DEFAULT NULL::text, p_archive_reason text DEFAULT NULL::text, p_original_office_id integer DEFAULT NULL::integer) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_contribution RECORD;
    v_archive_id BIGINT;
BEGIN
    -- Get contribution data
    SELECT * INTO v_contribution 
    FROM iebc_office_contributions 
    WHERE id = p_contribution_id;
    
    IF NOT FOUND THEN
        RETURN json_build_object('error', 'Contribution not found');
    END IF;
    
    -- Insert into archive table
    INSERT INTO contribution_archive (
        contribution_id,
        original_office_id,
        action_type,
        actor,
        review_notes,
        archive_reason,
        archived_data
    ) VALUES (
        p_contribution_id,
        p_original_office_id,
        p_action_type,
        p_actor,
        p_review_notes,
        p_archive_reason,
        jsonb_build_object(
            'submitted_office_location', v_contribution.submitted_office_location,
            'submitted_county', v_contribution.submitted_county,
            'submitted_constituency', v_contribution.submitted_constituency,
            'submitted_constituency_code', v_contribution.submitted_constituency_code,
            'submitted_landmark', v_contribution.submitted_landmark,
            'submitted_latitude', v_contribution.submitted_latitude,
            'submitted_longitude', v_contribution.submitted_longitude,
            'submitted_accuracy_meters', v_contribution.submitted_accuracy_meters,
            'google_maps_link', v_contribution.google_maps_link,
            'image_public_url', v_contribution.image_public_url,
            'device_metadata', v_contribution.device_metadata,
            'exif_metadata', v_contribution.exif_metadata,
            'reverse_geocode_result', v_contribution.reverse_geocode_result,
            'confidence_score', v_contribution.confidence_score,
            'duplicate_candidate_ids', v_contribution.duplicate_candidate_ids,
            'confirmation_count', v_contribution.confirmation_count,
            'status', v_contribution.status,
            'submission_source', v_contribution.submission_source,
            'submission_method', v_contribution.submission_method,
            'nearby_landmarks', v_contribution.nearby_landmarks,
            'submitted_timestamp', v_contribution.submitted_timestamp,
            'created_at', v_contribution.created_at
        )
    ) RETURNING id INTO v_archive_id;
    
    -- Mark contribution as archived
    UPDATE iebc_office_contributions 
    SET 
        is_archived = TRUE,
        archived_at = NOW(),
        archive_reason = p_archive_reason,
        original_office_id = p_original_office_id
    WHERE id = p_contribution_id;
    
    RETURN json_build_object(
        'success', true,
        'archive_id', v_archive_id,
        'contribution_id', p_contribution_id,
        'action', p_action_type
    );
END;
$$;


ALTER FUNCTION public.archive_contribution(p_contribution_id integer, p_action_type text, p_actor text, p_review_notes text, p_archive_reason text, p_original_office_id integer) OWNER TO postgres;

--
-- Name: auto_approve_contact_updates(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.auto_approve_contact_updates(min_confirmations integer DEFAULT 3) RETURNS TABLE(contact_update_id bigint, office_id bigint, phone text, email text, hours text, approval_count bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    cu.id AS contact_update_id,
    cu.office_id,
    cu.phone,
    cu.email,
    cu.hours,
    COUNT(DISTINCT cu2.id) AS approval_count
  FROM public.contact_update_requests cu
  JOIN public.contact_update_requests cu2
    ON cu.office_id = cu2.office_id
   AND cu.phone = cu2.phone
   AND cu.email = cu2.email
   AND cu.hours = cu2.hours
  WHERE cu.status = 'pending'
  GROUP BY
    cu.id,
    cu.office_id,
    cu.phone,
    cu.email,
    cu.hours
  HAVING COUNT(DISTINCT cu2.id) >= min_confirmations
  ORDER BY approval_count DESC;
END;
$$;


ALTER FUNCTION public.auto_approve_contact_updates(min_confirmations integer) OWNER TO postgres;

