--
-- Name: fetch_and_store_osm_landmarks(double precision, double precision, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fetch_and_store_osm_landmarks(p_lat double precision, p_lng double precision, p_radius_meters integer DEFAULT 2000) RETURNS TABLE(landmarks_added integer, total_landmarks integer)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $_$
DECLARE
    overpass_url text := 'https://overpass-api.de/api/interpreter';
    bbox_text text;
    overpass_query text;
    http_result text;
    response_json json;
    elements_json json;
    element_record json;
    new_landmark_count integer := 0;
    total_count integer := 0;
    landmark_type text;
    landmark_subtype text;
    feature_name text;
    feature_lat double precision;
    feature_lon double precision;
    accuracy_meters integer;
    visibility_score integer;
    permanence_score integer;
    triangulation_weight double precision;
BEGIN
    -- Calculate bounding box from center point and radius
    bbox_text := calculate_bounding_box(p_lat, p_lng, p_radius_meters);

    -- Build Overpass query using a single placeholder %BBOX% and safe dollar-quoting ($Q$...$Q$)
    overpass_query := replace($Q$
[out:json][timeout:120];
(
  /* Highways and transport */
  way["highway"]["highway"~"motorway|trunk|primary|secondary|tertiary|unclassified|residential|service|living_street|track"](%BBOX%);
  node["highway"="bus_stop"](%BBOX%);
  node["public_transport"~"platform|stop_position"](%BBOX%);
  node["railway"="station"](%BBOX%);
  way["railway"](%BBOX%);
  node["route"="ferry"](%BBOX%);
  node["aeroway"~"aerodrome|airport|helipad|seaplane"](%BBOX%);
  way["aeroway"](%BBOX%);

  /* Water and natural */
  way["waterway"](%BBOX%);
  way["natural"="water"](%BBOX%);
  node["natural"="spring"](%BBOX%);
  node["natural"~"peak|hill|volcano"](%BBOX%);
  way["natural"~"wood|forest|wetland|water"](%BBOX%);
  way["coastline"](%BBOX%);

  /* Administrative/Boundaries and land use */
  relation["boundary"="administrative"]["admin_level"~"2|3|4|5|6|7|8"](%BBOX%);
  way["landuse"](%BBOX%);
  way["leisure"~"park|recreation_ground|garden"](%BBOX%);

  /* Built environment & buildings */
  way["building"](%BBOX%);
  node["building"](%BBOX%);
  way["amenity"~"school|university|college|hospital|clinic|doctors|pharmacy|police|fire_station|post_office|library|townhall|courthouse"](%BBOX%);
  node["amenity"~"school|university|college|hospital|clinic|doctors|pharmacy|police|fire_station|post_office|library|townhall|courthouse"](%BBOX%);

  /* Commercial, retail, markets */
  node["shop"](%BBOX%);
  way["shop"](%BBOX%);
  node["amenity"~"restaurant|bank|atm|marketplace|cafe"](%BBOX%);
  way["amenity"~"restaurant|bank|atm|marketplace|cafe"](%BBOX%);

  /* Tourism, culture & historic */
  node["tourism"~"attraction|museum|viewpoint|information|hotel|guest_house|camp_site"](%BBOX%);
  way["tourism"~"attraction|museum|viewpoint|information|hotel|guest_house|camp_site"](%BBOX%);
  node["historic"](%BBOX%);
  way["historic"](%BBOX%);

  /* Religion, community, sports */
  node["amenity"="place_of_worship"](%BBOX%);
  way["amenity"="place_of_worship"](%BBOX%);
  node["leisure"~"stadium|sports_centre|playground"](%BBOX%);
  way["leisure"~"stadium|sports_centre|playground"](%BBOX%);

  /* Infrastructure, utilities, industrial */
  node["power"~"substation|generator|tower"](%BBOX%);
  way["power"~"line|minor_line|station"](%BBOX%);
  way["man_made"~"pier|breakwater|embankment|retaining_wall|sea_wall|works|wharf"](%BBOX%);
  node["communication"~"mast|tower"](%BBOX%);
  node["industrial"~"."](%BBOX%);
  way["aerialway"](%BBOX%);

  /* POI categories often useful for human reference */
  node["amenity"~"parking|car_rental|car_sharing"](%BBOX%);
  node["emergency"](%BBOX%);

  /* Buildings / addresses / names */
  node["addr:housenumber"](%BBOX%);
  node["name"](%BBOX%);  /* fallback: any named node */
);
out body;
out center;
>;
out skel qt;
$Q$, '%BBOX%', bbox_text);

    -- Perform HTTP POST to Overpass via http extension
    BEGIN
        SELECT content INTO http_result FROM http((
            'POST',
            overpass_url,
            ARRAY[http_header('Content-Type', 'application/x-www-form-urlencoded')],
            'application/x-www-form-urlencoded',
            'data=' || encode(overpass_query::bytea, 'base64')
        )::http_request);

        response_json := http_result::json;
        elements_json := response_json -> 'elements';

        -- Loop through returned elements
        FOR element_record IN SELECT * FROM json_array_elements(elements_json)
        LOOP
            total_count := total_count + 1;

            -- Map element to our landmark schema function
            SELECT *
            INTO landmark_type, landmark_subtype, feature_name,
                 feature_lat, feature_lon, accuracy_meters,
                 visibility_score, permanence_score, triangulation_weight
            FROM map_osm_element_to_landmark(element_record);

            IF feature_lat IS NOT NULL AND feature_lon IS NOT NULL AND landmark_type IS NOT NULL THEN
                -- Avoid duplicates by OSM id or proximity + type/subtype
                IF NOT EXISTS (
                    SELECT 1 FROM map_landmarks
                    WHERE osm_id = (element_record ->> 'id')::bigint
                    OR (
                        ST_DWithin(
                            centroid,
                            ST_SetSRID(ST_MakePoint(feature_lon, feature_lat), 4326)::geography,
                            50
                        )
                        AND landmark_type = map_osm_element_to_landmark.landmark_type
                        AND landmark_subtype = map_osm_element_to_landmark.landmark_subtype
                    )
                ) THEN
                    INSERT INTO map_landmarks (
                        osm_id, source, landmark_type, landmark_subtype,
                        name, centroid, tags, typical_accuracy_meters,
                        visibility_score, permanence_score, triangulation_weight, verified
                    ) VALUES (
                        (element_record ->> 'id')::bigint,
                        'osm_auto',
                        landmark_type,
                        landmark_subtype,
                        feature_name,
                        ST_SetSRID(ST_MakePoint(feature_lon, feature_lat), 4326)::geography,
                        element_record -> 'tags',
                        accuracy_meters,
                        visibility_score,
                        permanence_score,
                        triangulation_weight,
                        true
                    );
                    new_landmark_count := new_landmark_count + 1;
                END IF;
            END IF;
        END LOOP;

    EXCEPTION
        WHEN OTHERS THEN
            RAISE NOTICE 'Error fetching OSM data: %', SQLERRM;
            RETURN QUERY SELECT 0, 0;
            RETURN;
    END;

    RETURN QUERY SELECT new_landmark_count, total_count;
END;
$_$;


ALTER FUNCTION public.fetch_and_store_osm_landmarks(p_lat double precision, p_lng double precision, p_radius_meters integer) OWNER TO postgres;

--
-- Name: find_constituencies_near_point(double precision, double precision, double precision); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.find_constituencies_near_point(p_latitude double precision, p_longitude double precision, p_radius_km double precision DEFAULT 10) RETURNS TABLE(id integer, name text, county_name text, distance_km double precision)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    c.id,
    c.name::text,
    ct.name::text as county_name,
    ST_Distance(
      ST_SetSRID(ST_MakePoint(p_longitude, p_latitude), 4326)::geography,
      ST_SetSRID(ST_MakePoint(c.longitude, c.latitude), 4326)::geography
    ) / 1000 as distance_km
  FROM constituencies c
  JOIN counties ct ON c.county_id = ct.id
  WHERE ST_DWithin(
    ST_SetSRID(ST_MakePoint(p_longitude, p_latitude), 4326)::geography,
    ST_SetSRID(ST_MakePoint(c.longitude, c.latitude), 4326)::geography,
    p_radius_km * 1000
  )
  ORDER BY distance_km
  LIMIT 5;
END;
$$;


ALTER FUNCTION public.find_constituencies_near_point(p_latitude double precision, p_longitude double precision, p_radius_km double precision) OWNER TO postgres;

--
-- Name: find_constituencies_near_point(double precision, double precision, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.find_constituencies_near_point(p_latitude double precision, p_longitude double precision, p_radius_km integer DEFAULT 10) RETURNS TABLE(id integer, name text, county_name text, distance_km double precision)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        c.id,
        c.name,
        co.name as county_name,
        ST_Distance(
            ST_SetSRID(ST_MakePoint(p_longitude, p_latitude), 4326)::geography,
            ST_SetSRID(ST_MakePoint(c.centroid_longitude, c.centroid_latitude), 4326)::geography
        ) / 1000 as distance_km
    FROM constituencies c
    JOIN counties co ON c.county_id = co.id
    WHERE ST_DWithin(
        ST_SetSRID(ST_MakePoint(p_longitude, p_latitude), 4326)::geography,
        ST_SetSRID(ST_MakePoint(c.centroid_longitude, c.centroid_latitude), 4326)::geography,
        p_radius_km * 1000
    )
    ORDER BY distance_km
    LIMIT 5;
END;
$$;


