--
-- Name: fix_all_constituency_relationships(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fix_all_constituency_relationships() RETURNS TABLE(offices_updated bigint, contributions_updated bigint)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  office_count bigint;
  contribution_count bigint;
BEGIN
  -- Fix iebc_offices
  WITH updated_offices AS (
    UPDATE iebc_offices o
    SET constituency_code = get_or_create_constituency(o.constituency, o.county)
    WHERE constituency_code IS NULL 
      AND o.constituency IS NOT NULL 
      AND o.constituency != ''
    RETURNING 1
  )
  SELECT COUNT(*) INTO office_count FROM updated_offices;

  -- Fix iebc_office_contributions
  WITH updated_contributions AS (
    UPDATE iebc_office_contributions c
    SET submitted_constituency_code = get_or_create_constituency(
      c.submitted_constituency, 
      c.submitted_county
    )
    WHERE submitted_constituency_code IS NULL 
      AND c.submitted_constituency IS NOT NULL 
      AND c.submitted_constituency != ''
    RETURNING 1
  )
  SELECT COUNT(*) INTO contribution_count FROM updated_contributions;

  RETURN QUERY SELECT office_count, contribution_count;
END;
$$;


ALTER FUNCTION public.fix_all_constituency_relationships() OWNER TO postgres;

--
-- Name: fix_constituency_references(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fix_constituency_references() RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- Update iebc_offices with valid constituency codes
  UPDATE iebc_offices 
  SET constituency_code = c.id
  FROM constituencies c 
  WHERE iebc_offices.constituency = c.name 
    AND iebc_offices.constituency_code IS NULL;
    
  -- Update contributions with valid constituency IDs
  UPDATE iebc_office_contributions 
  SET submitted_constituency_id = c.id
  FROM constituencies c 
  WHERE iebc_office_contributions.submitted_constituency = c.name 
    AND iebc_office_contributions.submitted_constituency_id IS NULL;
END;
$$;


ALTER FUNCTION public.fix_constituency_references() OWNER TO postgres;

--
-- Name: get_archived_contributions(integer, integer, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_archived_contributions(p_limit integer DEFAULT 50, p_offset integer DEFAULT 0, p_action_type text DEFAULT NULL::text) RETURNS TABLE(archive_id bigint, contribution_id integer, original_office_id integer, action_type text, action_timestamp timestamp with time zone, actor text, review_notes text, archive_reason text, office_name text, county text, constituency text, archived_data jsonb)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        ca.id as archive_id,
        ca.contribution_id,
        ca.original_office_id,
        ca.action_type,
        ca.action_timestamp,
        ca.actor,
        ca.review_notes,
        ca.archive_reason,
        coc.submitted_office_location as office_name,
        coc.submitted_county as county,
        coc.submitted_constituency as constituency,
        ca.archived_data
    FROM contribution_archive ca
    JOIN iebc_office_contributions coc ON ca.contribution_id = coc.id
    WHERE (p_action_type IS NULL OR ca.action_type = p_action_type)
    ORDER BY ca.action_timestamp DESC
    LIMIT p_limit OFFSET p_offset;
END;
$$;


ALTER FUNCTION public.get_archived_contributions(p_limit integer, p_offset integer, p_action_type text) OWNER TO postgres;

