--
-- Name: get_optimal_triangulation_landmarks(double precision, double precision, double precision, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_optimal_triangulation_landmarks(p_lat double precision, p_lng double precision, p_radius_meters double precision DEFAULT 2000, p_max_landmarks integer DEFAULT 8) RETURNS TABLE(landmark_id bigint, landmark_name text, landmark_type text, landmark_subtype text, landmark_latitude double precision, landmark_longitude double precision, distance_meters double precision, bearing_degrees double precision, triangulation_weight double precision, quality_score double precision, direction_description text, side_of_road text, typical_accuracy_meters integer)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  RETURN QUERY
  WITH nearby_landmarks AS (
    SELECT
      io.id AS landmark_id,
      io.office_location AS landmark_name,
      'government' AS landmark_type,
      'iebc_office' AS landmark_subtype,
      COALESCE(io.verified_latitude, io.latitude) AS landmark_latitude,
      COALESCE(io.verified_longitude, io.longitude) AS landmark_longitude,
      ST_Distance(
        ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography,
        ST_SetSRID(ST_MakePoint(COALESCE(io.verified_longitude, io.longitude),
                                COALESCE(io.verified_latitude, io.latitude)), 4326)::geography
      ) AS distance_m,
      degrees(ST_Azimuth(
        ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326),
        ST_SetSRID(ST_MakePoint(COALESCE(io.verified_longitude, io.longitude),
                                COALESCE(io.verified_latitude, io.latitude)), 4326)
      )) AS bearing,
      0.85 AS triangulation_weight,
      15 AS typical_accuracy,
      (0.95 * 0.85 *
       (1 - (ST_Distance(
         ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography,
         ST_SetSRID(ST_MakePoint(COALESCE(io.verified_longitude, io.longitude),
                                 COALESCE(io.verified_latitude, io.latitude)), 4326)::geography
       ) / p_radius_meters))) AS calculated_quality_score,
      CASE
        WHEN ABS(COALESCE(io.verified_latitude, io.latitude) - p_lat) < 0.0001 THEN 'on_road'
        WHEN COALESCE(io.verified_latitude, io.latitude) > p_lat THEN 'east_side'
        ELSE 'west_side'
      END AS calculated_side_of_road
    FROM iebc_offices io
    WHERE io.verified = TRUE
      AND ST_DWithin(
        ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography,
        ST_SetSRID(ST_MakePoint(COALESCE(io.verified_longitude, io.longitude),
                                COALESCE(io.verified_latitude, io.latitude)), 4326)::geography,
        p_radius_meters
      )

    UNION ALL

    SELECT
      ml.id AS landmark_id,
      COALESCE(ml.name, ml.landmark_subtype) AS landmark_name,
      ml.landmark_type,
      ml.landmark_subtype,
      ST_Y(ml.centroid::geometry) AS landmark_latitude,
      ST_X(ml.centroid::geometry) AS landmark_longitude,
      ST_Distance(ml.centroid, ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography) AS distance_m,
      degrees(ST_Azimuth(ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326), ml.centroid::geometry)) AS bearing,
      ml.triangulation_weight,
      ml.typical_accuracy_meters AS typical_accuracy,
      (ml.triangulation_weight *
       (ml.visibility_score::float / 10) *
       (ml.permanence_score::float / 10) *
       (1 - (ST_Distance(ml.centroid,
                         ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography) / p_radius_meters))
      ) AS calculated_quality_score,
      'unknown' AS calculated_side_of_road
    FROM map_landmarks ml
    WHERE ml.verified = TRUE
      AND ST_DWithin(ml.centroid,
                     ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography,
                     p_radius_meters)
  ),
  ranked_landmarks AS (
    SELECT
      nl.*,
      ROW_NUMBER() OVER (
        PARTITION BY FLOOR(nl.bearing / 90), nl.landmark_type
        ORDER BY nl.calculated_quality_score DESC, nl.distance_m ASC
      ) AS sector_rank
    FROM nearby_landmarks nl
    WHERE nl.calculated_quality_score > 0.3
  )
  SELECT
    rl.landmark_id,
    rl.landmark_name,
    rl.landmark_type,
    rl.landmark_subtype,
    rl.landmark_latitude,
    rl.landmark_longitude,
    rl.distance_m AS distance_meters,
    rl.bearing AS bearing_degrees,
    rl.triangulation_weight,
    rl.calculated_quality_score AS quality_score,
    CASE
      WHEN rl.bearing BETWEEN 337.5 AND 22.5 THEN 'North'
      WHEN rl.bearing BETWEEN 22.5 AND 67.5 THEN 'North-East'
      WHEN rl.bearing BETWEEN 67.5 AND 112.5 THEN 'East'
      WHEN rl.bearing BETWEEN 112.5 AND 157.5 THEN 'South-East'
      WHEN rl.bearing BETWEEN 157.5 AND 202.5 THEN 'South'
      WHEN rl.bearing BETWEEN 202.5 AND 247.5 THEN 'South-West'
      WHEN rl.bearing BETWEEN 247.5 AND 292.5 THEN 'West'
      ELSE 'North-West'
    END || ' of your position' AS direction_description,
    rl.calculated_side_of_road AS side_of_road,
    rl.typical_accuracy AS typical_accuracy_meters
  FROM ranked_landmarks rl
  WHERE rl.sector_rank <= 2
  ORDER BY rl.calculated_quality_score DESC, rl.distance_m ASC
  LIMIT p_max_landmarks;
END;
$$;


ALTER FUNCTION public.get_optimal_triangulation_landmarks(p_lat double precision, p_lng double precision, p_radius_meters double precision, p_max_landmarks integer) OWNER TO postgres;

--
-- Name: get_or_create_constituency(text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_or_create_constituency(constituency_name text, county_name text DEFAULT NULL::text) RETURNS integer
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
    constituency_id integer;
    county_id integer;
    normalized_county text := UPPER(TRIM(COALESCE(county_name, '')));
    normalized_const text := UPPER(TRIM(COALESCE(constituency_name, '')));
BEGIN
    -- find county by normalized_name or fuzzy match
    SELECT id INTO county_id
    FROM public.counties
    WHERE normalized_name = normalized_county
       OR name ILIKE '%' || TRIM(COALESCE(county_name, '')) || '%'
    LIMIT 1;

    IF county_id IS NULL THEN
        -- fallback to Nairobi if available
        SELECT id INTO county_id FROM public.counties WHERE normalized_name = 'NAIROBI' LIMIT 1;
    END IF;

    -- find existing constituency
    SELECT c.id INTO constituency_id
    FROM public.constituencies c
    WHERE c.county_id = county_id
      AND (c.normalized_name = normalized_const
           OR c.name ILIKE '%' || TRIM(COALESCE(constituency_name, '')) || '%')
    LIMIT 1;

    IF constituency_id IS NOT NULL THEN
        RETURN constituency_id;
    END IF;

    -- attempt insert with concurrency-safe fallback
    BEGIN
        INSERT INTO public.constituencies (name, county_id, normalized_name, centroid_latitude, centroid_longitude)
        VALUES (
            TRIM(COALESCE(constituency_name, '')),
            county_id,
            normalized_const,
            -1.3002258,
            36.7733847
        )
        RETURNING id INTO constituency_id;
    EXCEPTION WHEN unique_violation THEN
        SELECT id INTO constituency_id
        FROM public.constituencies
        WHERE county_id = county_id
          AND normalized_name = normalized_const
        LIMIT 1;
    END;

    RETURN constituency_id;
END;
$$;


ALTER FUNCTION public.get_or_create_constituency(constituency_name text, county_name text) OWNER TO postgres;

--
-- Name: get_pending_contributions(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_pending_contributions(limit_count integer DEFAULT 50) RETURNS TABLE(id bigint, office_id bigint, submitted_office_location text, submitted_county text, submitted_constituency text, submitted_latitude double precision, submitted_longitude double precision, confidence_score integer, confirmation_count integer, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    c.id,
    c.original_office_id AS office_id,
    c.submitted_office_location,
    c.submitted_county,
    c.submitted_constituency,
    c.submitted_latitude,
    c.submitted_longitude,
    c.confidence_score,
    COUNT(DISTINCT conf.id)::INTEGER AS confirmation_count,
    c.created_at
  FROM public.iebc_office_contributions c
  LEFT JOIN public.confirmations conf
    ON c.id = conf.contribution_id
  WHERE c.status = 'pending_review'
  GROUP BY
    c.id,
    c.original_office_id,
    c.submitted_office_location,
    c.submitted_county,
    c.submitted_constituency,
    c.submitted_latitude,
    c.submitted_longitude,
    c.confidence_score,
    c.created_at
  ORDER BY
    c.confidence_score DESC,
    confirmation_count DESC,
    c.created_at ASC
  LIMIT limit_count;
END;
$$;


ALTER FUNCTION public.get_pending_contributions(limit_count integer) OWNER TO postgres;

--
-- Name: FUNCTION get_pending_contributions(limit_count integer); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.get_pending_contributions(limit_count integer) IS 'Get contributions pending review with confirmation counts';


--
-- Name: get_trending_contributions(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_trending_contributions(days_back integer DEFAULT 7, limit_count integer DEFAULT 10) RETURNS TABLE(contribution_id bigint, office_id bigint, office_location text, county text, upvotes bigint, downvotes bigint, helpful_votes bigint, created_at timestamp with time zone, score numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    c.id AS contribution_id,
    c.original_office_id AS office_id,
    c.submitted_office_location AS office_location,
    c.submitted_county AS county,
    COUNT(CASE WHEN cv.vote_type = 'upvote' THEN 1 END) AS upvotes,
    COUNT(CASE WHEN cv.vote_type = 'downvote' THEN 1 END) AS downvotes,
    COUNT(CASE WHEN cv.vote_type = 'helpful' THEN 1 END) AS helpful_votes,
    c.created_at,
    (
      COUNT(CASE WHEN cv.vote_type = 'upvote' THEN 1 END) * 2
      + COUNT(CASE WHEN cv.vote_type = 'helpful' THEN 1 END) * 1.5
      - COUNT(CASE WHEN cv.vote_type = 'downvote' THEN 1 END) * 1
    ) AS score
  FROM public.iebc_office_contributions c
  LEFT JOIN public.contribution_votes cv
    ON c.id = cv.contribution_id
  WHERE c.created_at > NOW() - (days_back || ' days')::INTERVAL
  GROUP BY
    c.id,
    c.original_office_id,
    c.submitted_office_location,
    c.submitted_county,
    c.created_at
  ORDER BY score DESC, c.created_at DESC
  LIMIT limit_count;
END;
$$;


ALTER FUNCTION public.get_trending_contributions(days_back integer, limit_count integer) OWNER TO postgres;

--
-- Name: FUNCTION get_trending_contributions(days_back integer, limit_count integer); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.get_trending_contributions(days_back integer, limit_count integer) IS 'Get trending contributions based on votes and recency';


