--
-- Name: insert_index_usage_data(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.insert_index_usage_data() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  INSERT INTO index_usage_monitoring (data)
  SELECT jsonb_agg(to_jsonb(results))
  FROM (
    WITH index_stats AS (
      SELECT 
        now() AS check_time,
        schemaname,
        relname AS table_name,
        indexrelname AS index_name,
        idx_scan,
        idx_tup_read,
        idx_tup_fetch,
        pg_relation_size(indexrelid) AS index_size_bytes,
        pg_size_pretty(pg_relation_size(indexrelid)) AS index_size_pretty,
        CASE 
          WHEN indexrelid IN (
            SELECT conindid
            FROM pg_constraint
            WHERE contype = 'f'
          ) THEN 'YES'
          ELSE 'NO'
        END AS is_foreign_key,
        (SELECT pg_get_indexdef(i.indexrelid)) AS index_definition
      FROM pg_stat_all_indexes i
      WHERE indexrelname IN (
        'idx_audit_trail_petition_id', 'idx_audit_trail_signature_id', 'idx_audit_trail_user_id',
        'idx_evidence_documents_uploaded_by', 'idx_petitions_county', 'idx_petitions_created_by',
        'idx_petitions_signature_target', 'idx_wards_member_of_parliament', 'idx_petitions_constituency_fkey'
      )
    ),
    size_summary AS (
      SELECT
        pg_size_pretty(SUM(index_size_bytes)) AS total_size,
        COUNT(*) AS index_count
      FROM index_stats
    )
    SELECT 
      s.*,
      ss.total_size,
      ss.index_count,
      (SELECT pg_postmaster_start_time() AS db_start_time)
    FROM index_stats s
    CROSS JOIN size_summary ss
    ORDER BY 
      s.is_foreign_key DESC,
      s.idx_scan ASC,
      s.index_size_bytes DESC
  ) results;
END;
$$;


ALTER FUNCTION public.insert_index_usage_data() OWNER TO postgres;

