--
-- Name: map_osm_element_to_landmark(json); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.map_osm_element_to_landmark(element_data json) RETURNS TABLE(landmark_type text, landmark_subtype text, name text, latitude double precision, longitude double precision, accuracy_meters integer, visibility_score integer, permanence_score integer, triangulation_weight double precision)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
    tags json;
    element_type text;
    center_lat double precision;
    center_lon double precision;
BEGIN
    tags := element_data -> 'tags';
    element_type := element_data ->> 'type';
    
    -- Extract coordinates for node / way / relation (use center where available)
    IF element_type = 'node' THEN
        IF (element_data ->> 'lat') IS NULL OR (element_data ->> 'lon') IS NULL THEN
            RETURN; -- no coordinates
        END IF;
        center_lat := (element_data ->> 'lat')::double precision;
        center_lon := (element_data ->> 'lon')::double precision;
        
    ELSIF element_type = 'way' OR element_type = 'relation' THEN
        IF element_data ? 'center' THEN
            center_lat := (element_data -> 'center' ->> 'lat')::double precision;
            center_lon := (element_data -> 'center' ->> 'lon')::double precision;
        ELSIF element_data ? 'geometry' AND json_array_length(element_data -> 'geometry') > 0 THEN
            center_lat := (element_data -> 'geometry' -> 0 ->> 'lat')::double precision;
            center_lon := (element_data -> 'geometry' -> 0 ->> 'lon')::double precision;
        ELSIF element_data ? 'bounds' THEN
            -- use bounding box center if available
            center_lat := (((element_data -> 'bounds' ->> 'minlat')::double precision + (element_data -> 'bounds' ->> 'maxlat')::double precision) / 2.0);
            center_lon := (((element_data -> 'bounds' ->> 'minlon')::double precision + (element_data -> 'bounds' ->> 'maxlon')::double precision) / 2.0);
        ELSE
            RETURN; -- no usable coordinate
        END IF;
    ELSE
        RETURN; -- unsupported element type
    END IF;
    
    -- Extract name or useful identifiers
    name := COALESCE(
        tags ->> 'name',
        tags ->> 'name:en',
        tags ->> 'ref',
        tags ->> 'operator',
        tags ->> 'addr:housename',
        tags ->> 'addr:housenumber'
    );

    -- Default baseline (if nothing matches)
    accuracy_meters := 25;
    visibility_score := 5;
    permanence_score := 6;
    triangulation_weight := 0.5;

    -- Map common OSM tags to landmark types and set heuristics
    IF tags IS NOT NULL AND tags ->> 'highway' IS NOT NULL THEN
        landmark_type := 'road';
        landmark_subtype := tags ->> 'highway';
        accuracy_meters := 8;
        visibility_score := 9;
        permanence_score := 10;
        triangulation_weight := 0.85;

    ELSIF tags IS NOT NULL AND tags ->> 'railway' IS NOT NULL THEN
        landmark_type := 'railway';
        landmark_subtype := tags ->> 'railway';
        accuracy_meters := 8;
        visibility_score := 9;
        permanence_score := 10;
        triangulation_weight := 0.85;

    ELSIF tags IS NOT NULL AND tags ->> 'aeroway' IS NOT NULL THEN
        landmark_type := 'aeroway';
        landmark_subtype := tags ->> 'aeroway';
        accuracy_meters := 20;
        visibility_score := 10;
        permanence_score := 10;
        triangulation_weight := 0.9;

    ELSIF tags IS NOT NULL AND tags ->> 'waterway' IS NOT NULL THEN
        landmark_type := 'waterway';
        landmark_subtype := tags ->> 'waterway';
        accuracy_meters := 15;
        visibility_score := 7;
        permanence_score := 9;
        triangulation_weight := 0.7;

    ELSIF tags IS NOT NULL AND tags ->> 'natural' IS NOT NULL THEN
        landmark_type := 'natural';
        landmark_subtype := tags ->> 'natural';
        accuracy_meters := CASE WHEN tags ->> 'natural' = 'peak' THEN 5 ELSE 15 END;
        visibility_score := 8;
        permanence_score := 10;
        triangulation_weight := 0.85;

    ELSIF tags IS NOT NULL AND tags ->> 'landuse' IS NOT NULL THEN
        landmark_type := 'landuse';
        landmark_subtype := tags ->> 'landuse';
        accuracy_meters := 25;
        visibility_score := 6;
        permanence_score := 8;
        triangulation_weight := 0.6;

    ELSIF tags IS NOT NULL AND tags ->> 'amenity' IS NOT NULL THEN
        landmark_type := 'amenity';
        landmark_subtype := tags ->> 'amenity';
        accuracy_meters := 10;
        visibility_score := 9;
        permanence_score := 9;
        triangulation_weight := CASE 
            WHEN tags ->> 'amenity' IN ('hospital','police','fire_station','townhall','courthouse') THEN 0.9
            WHEN tags ->> 'amenity' IN ('school','university') THEN 0.85
            ELSE 0.75
        END;

    ELSIF tags IS NOT NULL AND tags ->> 'shop' IS NOT NULL THEN
        landmark_type := 'shop';
        landmark_subtype := tags ->> 'shop';
        accuracy_meters := 12;
        visibility_score := 7;
        permanence_score := 7;
        triangulation_weight := 0.65;

    ELSIF tags IS NOT NULL AND tags ->> 'tourism' IS NOT NULL THEN
        landmark_type := 'tourism';
        landmark_subtype := tags ->> 'tourism';
        accuracy_meters := 12;
        visibility_score := 8;
        permanence_score := 8;
        triangulation_weight := 0.75;

    ELSIF tags IS NOT NULL AND tags ->> 'historic' IS NOT NULL THEN
        landmark_type := 'historic';
        landmark_subtype := tags ->> 'historic';
        accuracy_meters := 10;
        visibility_score := 8;
        permanence_score := 9;
        triangulation_weight := 0.78;

    ELSIF tags IS NOT NULL AND tags ->> 'leisure' IS NOT NULL THEN
        landmark_type := 'leisure';
        landmark_subtype := tags ->> 'leisure';
        accuracy_meters := 20;
        visibility_score := 6;
        permanence_score := 7;
        triangulation_weight := 0.6;

    ELSIF tags IS NOT NULL AND tags ->> 'power' IS NOT NULL THEN
        landmark_type := 'infrastructure';
        landmark_subtype := tags ->> 'power';
        accuracy_meters := 10;
        visibility_score := 9;
        permanence_score := 10;
        triangulation_weight := 0.88;

    ELSIF tags IS NOT NULL AND tags ->> 'man_made' IS NOT NULL THEN
        landmark_type := 'man_made';
        landmark_subtype := tags ->> 'man_made';
        accuracy_meters := 12;
        visibility_score := 7;
        permanence_score := 9;
        triangulation_weight := 0.75;

    ELSIF tags IS NOT NULL AND tags ->> 'communication' IS NOT NULL THEN
        landmark_type := 'communication';
        landmark_subtype := tags ->> 'communication';
        accuracy_meters := 10;
        visibility_score := 9;
        permanence_score := 10;
        triangulation_weight := 0.85;

    ELSIF tags IS NOT NULL AND tags ->> 'addr:housenumber' IS NOT NULL THEN
        landmark_type := 'address';
        landmark_subtype := COALESCE(tags ->> 'addr:street', 'address');
        -- address points are quite precise but transient
        accuracy_meters := 5;
        visibility_score := 6;
        permanence_score := 6;
        triangulation_weight := 0.6;

    ELSIF tags IS NOT NULL AND tags ->> 'boundary' IS NOT NULL THEN
        landmark_type := 'boundary';
        landmark_subtype := COALESCE(tags ->> 'admin_level', tags ->> 'boundary');
        accuracy_meters := 30;
        visibility_score := 4;
        permanence_score := 9;
        triangulation_weight := 0.6;

    ELSIF tags IS NOT NULL AND tags ->> 'building' IS NOT NULL THEN
        landmark_type := 'building';
        landmark_subtype := tags ->> 'building';
        accuracy_meters := 8;
        visibility_score := 8;
        permanence_score := 9;
        triangulation_weight := 0.8;

    ELSIF tags IS NOT NULL AND (tags ->> 'emergency') IS NOT NULL THEN
        landmark_type := 'emergency';
        landmark_subtype := tags ->> 'emergency';
        accuracy_meters := 12;
        visibility_score := 8;
        permanence_score := 9;
        triangulation_weight := 0.8;

    -- fallback: any element with a name should be considered a POI
    ELSIF name IS NOT NULL THEN
        landmark_type := 'poi';
        landmark_subtype := NULL;
        accuracy_meters := 20;
        visibility_score := 6;
        permanence_score := 6;
        triangulation_weight := 0.55;

    ELSE
        -- Skip unmapped elements
        RETURN;
    END IF;
    
    -- Return the mapped values
    RETURN QUERY SELECT 
        landmark_type, landmark_subtype, name,
        center_lat, center_lon, accuracy_meters,
        visibility_score, permanence_score, triangulation_weight;
END;
$$;


ALTER FUNCTION public.map_osm_element_to_landmark(element_data json) OWNER TO postgres;

--
-- Name: nearby_offices(double precision, double precision, double precision); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.nearby_offices(lat double precision, lng double precision, radius_meters double precision DEFAULT 50000) RETURNS TABLE(id bigint, county text, constituency text, office_location text, latitude double precision, longitude double precision, distance_meters double precision, verified boolean)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    o.id,
    o.county,
    o.constituency,
    o.office_location,
    o.latitude,
    o.longitude,
    ST_Distance(
      o.geom::geography,
      ST_SetSRID(ST_MakePoint(lng, lat), 4326)::geography
    ) AS distance_meters,
    o.verified
  FROM public.iebc_offices o
  WHERE o.latitude IS NOT NULL
    AND o.longitude IS NOT NULL
    AND ST_DWithin(
      o.geom::geography,
      ST_SetSRID(ST_MakePoint(lng, lat), 4326)::geography,
      radius_meters
    )
  ORDER BY distance_meters ASC
  LIMIT 100;
END;
$$;


ALTER FUNCTION public.nearby_offices(lat double precision, lng double precision, radius_meters double precision) OWNER TO postgres;

