--
-- Name: search_offices_fuzzy(text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.search_offices_fuzzy(search_term text, limit_count integer DEFAULT 20) RETURNS TABLE(id bigint, county text, constituency_name text, office_location text, latitude double precision, longitude double precision, formatted_address text, match_score real)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    o.id,
    o.county,
    o.constituency_name,
    o.office_location,
    o.latitude,
    o.longitude,
    o.formatted_address,
    (
      CASE
        WHEN LOWER(o.county) LIKE '%' || LOWER(search_term) || '%' THEN 3.0
        WHEN LOWER(o.constituency_name) LIKE '%' || LOWER(search_term) || '%' THEN 2.5
        WHEN LOWER(o.office_location) LIKE '%' || LOWER(search_term) || '%' THEN 2.0
        WHEN LOWER(o.landmark) LIKE '%' || LOWER(search_term) || '%' THEN 1.5
        WHEN LOWER(o.formatted_address) LIKE '%' || LOWER(search_term) || '%' THEN 1.0
        ELSE 0.5
      END
    ) AS match_score
  FROM public.iebc_offices o
  WHERE o.verified = true
    AND (
      LOWER(o.county) LIKE '%' || LOWER(search_term) || '%'
      OR LOWER(o.constituency_name) LIKE '%' || LOWER(search_term) || '%'
      OR LOWER(o.office_location) LIKE '%' || LOWER(search_term) || '%'
      OR LOWER(o.landmark) LIKE '%' || LOWER(search_term) || '%'
      OR LOWER(o.formatted_address) LIKE '%' || LOWER(search_term) || '%'
    )
  ORDER BY match_score DESC, o.county, o.constituency_name
  LIMIT limit_count;
END;
$$;


