COMMENT ON FUNCTION public.search_offices_fuzzy(search_term text, limit_count integer) IS 'Fuzzy text search across office fields with relevance scoring';


--
-- Name: submit_signature(uuid, text, text, text, text, jsonb, text, jsonb, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.submit_signature(petition_id uuid, voter_id text, voter_name text, constituency text, ward text, signature_payload jsonb, signature_value text, public_key jsonb, key_version text, device_id text) RETURNS uuid
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  signature_id UUID;
  existing_count INT;
BEGIN
  -- Check for existing signature
  SELECT COUNT(*) INTO existing_count
  FROM public.signatures
  WHERE petition_id = petition_id
    AND voter_id = voter_id;
  
  IF existing_count > 0 THEN
    RAISE EXCEPTION 'DUPLICATE_SIGNATURE';
  END IF;

  -- Insert new signature
  INSERT INTO public.signatures (
    petition_id,
    voter_id,
    voter_name,
    constituency,
    ward,
    signature_payload,
    signature_value,
    public_key,
    key_version,
    device_id,
    verification_status
  ) VALUES (
    petition_id,
    voter_id,
    voter_name,
    constituency,
    ward,
    signature_payload,
    signature_value,
    public_key,
    key_version,
    device_id,
    '{"verified": true, "method": "digital_signature", "timestamp": NOW()}'
  ) RETURNING id INTO signature_id;

  RETURN signature_id;
END;
$$;


ALTER FUNCTION public.submit_signature(petition_id uuid, voter_id text, voter_name text, constituency text, ward text, signature_payload jsonb, signature_value text, public_key jsonb, key_version text, device_id text) OWNER TO postgres;

