    csp_provider text NOT NULL,
    signature_certificate text,
    geolocation jsonb,
    device_fingerprint jsonb,
    signature_timestamp timestamp with time zone DEFAULT now() NOT NULL,
    blockchain_hash text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    signature_payload jsonb,
    signature_value text,
    public_key jsonb,
    key_version text,
