20250714015004	{"-- Drop and recreate policies properly\nDROP POLICY IF EXISTS \\"Anyone can view active petitions\\" ON public.petitions;\nDROP POLICY IF EXISTS \\"Authenticated users can create petitions\\" ON public.petitions;\nDROP POLICY IF EXISTS \\"Petition creators can update their petitions\\" ON public.petitions;\nDROP POLICY IF EXISTS \\"Anyone can create petitions\\" ON public.petitions;\nDROP POLICY IF EXISTS \\"Public petition updates\\" ON public.petitions;\n\n-- Create new public policies for petitions\nCREATE POLICY \\"Public can view active petitions\\" \nON public.petitions \nFOR SELECT \nUSING (status = 'active');\n\nCREATE POLICY \\"Public can create petitions\\" \nON public.petitions \nFOR INSERT \nWITH CHECK (true);\n\nCREATE POLICY \\"Public can update petitions\\" \nON public.petitions \nFOR UPDATE \nUSING (true);\n\n-- Update signatures policies\nDROP POLICY IF EXISTS \\"Authenticated users can create signatures\\" ON public.signatures;\nDROP POLICY IF EXISTS \\"Anyone can create signatures\\" ON public.signatures;\n\nCREATE POLICY \\"Public can create signatures\\" \nON public.signatures \nFOR INSERT \nWITH CHECK (true);"}		saemscodes@gmail.com	\N
20250716120015	{"\n-- Drop existing policies on counties table\nDROP POLICY IF EXISTS \\"Enable public read access\\" ON public.counties;\n\n-- Drop existing policies on constituencies table  \nDROP POLICY IF EXISTS \\"Enable public read access\\" ON public.constituencies;\n\n-- Create comprehensive public access policies for counties\nCREATE POLICY \\"Public can view all counties\\" \nON public.counties \nFOR SELECT \nUSING (true);\n\nCREATE POLICY \\"Public can insert counties\\" \nON public.counties \nFOR INSERT \nWITH CHECK (true);\n\nCREATE POLICY \\"Public can update counties\\" \nON public.counties \nFOR UPDATE \nUSING (true);\n\nCREATE POLICY \\"Public can delete counties\\" \nON public.counties \nFOR DELETE \nUSING (true);\n\n-- Create comprehensive public access policies for constituencies\nCREATE POLICY \\"Public can view all constituencies\\" \nON public.constituencies \nFOR SELECT \nUSING (true);\n\nCREATE POLICY \\"Public can insert constituencies\\" \nON public.constituencies \nFOR INSERT \nWITH CHECK (true);\n\nCREATE POLICY \\"Public can update constituencies\\" \nON public.constituencies \nFOR UPDATE \nUSING (true);\n\nCREATE POLICY \\"Public can delete constituencies\\" \nON public.constituencies \nFOR DELETE \nUSING (true);\n"}		saemscodes@gmail.com	\N
20250718020020	{"\n-- Create the evidence storage bucket that's missing\nINSERT INTO storage.buckets (id, name, public, file_size_limit, allowed_mime_types)\nVALUES (\n  'evidence',\n  'evidence',\n  false,\n  10485760, -- 10MB limit\n  ARRAY['application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document', 'image/jpeg', 'image/png', 'image/gif']\n);\n\n-- Create storage policies for evidence bucket\nCREATE POLICY \\"Authenticated users can upload evidence files\\"\nON storage.objects\nFOR INSERT\nWITH CHECK (\n  bucket_id = 'evidence' AND\n  auth.uid() IS NOT NULL\n);\n\nCREATE POLICY \\"Authenticated users can view evidence files\\"\nON storage.objects\nFOR SELECT\nUSING (\n  bucket_id = 'evidence' AND\n  auth.uid() IS NOT NULL\n);\n\nCREATE POLICY \\"Authenticated users can update their evidence files\\"\nON storage.objects\nFOR UPDATE\nUSING (\n  bucket_id = 'evidence' AND\n  auth.uid() IS NOT NULL\n);\n\nCREATE POLICY \\"Authenticated users can delete their evidence files\\"\nON storage.objects\nFOR DELETE\nUSING (\n  bucket_id = 'evidence' AND\n  auth.uid() IS NOT NULL\n);\n"}		saemscodes@gmail.com	\N
20250823085549	{"\n-- Fix the search_path mutability warnings by setting search_path explicitly\n\n-- Update the is_admin_user function (the one that takes user_id parameter)\nCREATE OR REPLACE FUNCTION public.is_admin_user(user_id uuid)\n RETURNS boolean\n LANGUAGE sql\n SECURITY DEFINER\n SET search_path TO 'public'\nAS $function$\n  SELECT EXISTS (\n    SELECT 1 FROM core_team \n    WHERE core_team.user_id = is_admin_user.user_id \n    AND core_team.is_admin = true\n  );\n$function$;\n\n-- Update the is_admin_user function (the one with no parameters)\nCREATE OR REPLACE FUNCTION public.is_admin_user()\n RETURNS boolean\n LANGUAGE plpgsql\n SECURITY DEFINER\n SET search_path TO 'public'\nAS $function$\nBEGIN\n    -- Your existing function logic here\n    RETURN true; -- Replace with actual admin check logic\nEND;\n$function$;\n\n-- Update the proper_case function\nCREATE OR REPLACE FUNCTION public.proper_case(name text)\n RETURNS text\n LANGUAGE plpgsql\n SET search_path TO 'public'\nAS $function$\nBEGIN\n  IF name IS NULL THEN RETURN NULL; END IF;\n  RETURN initcap(lower(name));\nEND;\n$function$;\n"}		saemscodes@gmail.com	\N
20250831012539	{"-- CRITICAL SECURITY FIXES\n\n-- 1. FIX SIGNATURES TABLE - Remove public read access to protect voter PII\nDROP POLICY IF EXISTS \\"Anyone can view signature counts\\" ON public.signatures;\n\n-- Create restricted policies for signatures table\nCREATE POLICY \\"Admin can view all signatures\\" \n  ON public.signatures \n  FOR SELECT \n  USING (\n    auth.uid() IN (\n      SELECT user_id FROM core_team WHERE is_admin = true\n    )\n  );\n\nCREATE POLICY \\"Users can view signatures by code\\" \n  ON public.signatures \n  FOR SELECT \n  USING (\n    -- Allow access when querying by signature_code only (app logic will handle this)\n    true -- This will be restricted in application logic for signature verification\n  );\n\n-- 2. FIX COUNTIES TABLE - Remove public write access\nDROP POLICY IF EXISTS \\"Public can insert counties\\" ON public.counties;\nDROP POLICY IF EXISTS \\"Public can update counties\\" ON public.counties;\nDROP POLICY IF EXISTS \\"Public can delete counties\\" ON public.counties;\n\n-- Create admin-only write policies for counties\nCREATE POLICY \\"Admin can modify counties\\" \n  ON public.counties \n  FOR ALL \n  USING (\n    auth.uid() IN (\n      SELECT user_id FROM core_team WHERE is_admin = true\n    )\n  )\n  WITH CHECK (\n    auth.uid() IN (\n      SELECT user_id FROM core_team WHERE is_admin = true\n    )\n  );\n\n-- 3. FIX CONSTITUENCIES TABLE - Remove public write access\nDROP POLICY IF EXISTS \\"Public can insert constituencies\\" ON public.constituencies;\nDROP POLICY IF EXISTS \\"Public can update constituencies\\" ON public.constituencies;\nDROP POLICY IF EXISTS \\"Public can delete constituencies\\" ON public.constituencies;\n\n-- Create admin-only write policies for constituencies\nCREATE POLICY \\"Admin can modify constituencies\\" \n  ON public.constituencies \n  FOR ALL \n  USING (\n    auth.uid() IN (\n      SELECT user_id FROM core_team WHERE is_admin = true\n    )\n  )\n  WITH CHECK (\n    auth.uid() IN (\n      SELECT user_id FROM core_team WHERE is_admin = true\n    )\n  );\n\n-- 4. FIX EVIDENCE DOCUMENTS - Restrict read access\nDROP POLICY IF EXISTS \\"Evidence documents read\\" ON public.evidence_documents;\n\n-- Create restricted read policy for evidence documents\nCREATE POLICY \\"Evidence documents restricted read\\" \n  ON public.evidence_documents \n  FOR SELECT \n  USING (\n    -- Admin users can see all\n    auth.uid() IN (\n      SELECT user_id FROM core_team WHERE is_admin = true\n    )\n    OR\n    -- Petition creators can see their petition's evidence\n    petition_id IN (\n      SELECT id FROM petitions WHERE created_by = auth.uid()\n    )\n    OR\n    -- Document uploaders can see their own uploads\n    uploaded_by = auth.uid()\n  );\n\n-- 5. ADD AUDIT LOGGING FOR SIGNATURE ACCESS\nCREATE TABLE IF NOT EXISTS public.signature_access_log (\n  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,\n  signature_id UUID REFERENCES signatures(id),\n  accessed_by UUID,\n  access_method TEXT NOT NULL,\n  access_timestamp TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now(),\n  ip_address INET,\n  user_agent TEXT\n);\n\nALTER TABLE public.signature_access_log ENABLE ROW LEVEL SECURITY;\n\nCREATE POLICY \\"Admin can view access logs\\" \n  ON public.signature_access_log \n  FOR SELECT \n  USING (\n    auth.uid() IN (\n      SELECT user_id FROM core_team WHERE is_admin = true\n    )\n  );\n\nCREATE POLICY \\"System can insert access logs\\" \n  ON public.signature_access_log \n  FOR INSERT \n  WITH CHECK (true);"}		saemscodes@gmail.com	\N
20251021013641	{"-- Create missing update timestamp function\nCREATE OR REPLACE FUNCTION update_iebc_office_contributions_updated_at()\nRETURNS TRIGGER AS $$\nBEGIN\n  NEW.updated_at = now();\n  RETURN NEW;\nEND;\n$$ LANGUAGE plpgsql;\n\n-- Create iebc-contributions storage bucket if not exists\nINSERT INTO storage.buckets (id, name, public, file_size_limit, allowed_mime_types)\nVALUES (\n  'iebc-contributions',\n  'iebc-contributions', \n  true,\n  10485760, -- 10MB\n  ARRAY['image/jpeg', 'image/png', 'image/webp', 'image/jpg']\n)\nON CONFLICT (id) DO NOTHING;\n\n-- Create storage policies for iebc-contributions bucket\nCREATE POLICY \\"Anyone can upload contribution images\\"\nON storage.objects FOR INSERT \nWITH CHECK (bucket_id = 'iebc-contributions');\n\nCREATE POLICY \\"Anyone can view contribution images\\"\nON storage.objects FOR SELECT\nUSING (bucket_id = 'iebc-contributions');\n\nCREATE POLICY \\"Users can update their own contribution images\\"\nON storage.objects FOR UPDATE\nUSING (bucket_id = 'iebc-contributions');\n\nCREATE POLICY \\"Admins can delete contribution images\\"\nON storage.objects FOR DELETE\nUSING (bucket_id = 'iebc-contributions' AND auth.role() = 'authenticated');"}		saemscodes@gmail.com	\N
